```javascript
// Specifying preferred codecs in WebRTC
const transceiver = peerConnection.addTransceiver('video');
const { codecpPreferences } = RTCRtpReceiver.getCapabilities('video');
// Filter for H264 to ensure hardware acceleration
const filtered = codecpPreferences.filter(c => c.mimeType === 'video/H264');
transceiver.setCodecPreferences(filtered);
```

